var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"메스헤르츠 채널에서 전해드리는 속보입니다.","JPN":"マスヘルツチャンネルからの速報です。","ENG":"Breaking news, here from the Masshertz channel.","TWN":"來自梅斯赫茲頻道的快報。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"금일 갑작스러운 침식사태 발발로 인해 소란이 빚어지고 있는 가운데, SNS 등지에서는 또다른 소식으로 논란이 불거지고 있습니다.","JPN":"本日、侵食事態騒動が起きている中、SNSなどでは別の話題が広まっています。","ENG":"The abrupt Corruption disaster that occurred today has been causing chaos, while the citizens are in disarray from the news that has been spreading through social media.","TWN":"今天突然爆發的侵蝕事件讓市民一片譁然，而同時在社群網路上傳出的另一個消息引發了爭議。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드 관리국의 시니어로 알려진 인물이 살해되었으며, 이 현장을 캡처한 다수의 사진들이 유포된 것인데요.","JPN":"シャレード管理局のシニアと思わしき人物が殺害され、その現場を撮影した写真が多数流布されました。","ENG":"A man, known as the Senior of Charade City Management, has been found murdered, and several pictures of the crime scene have been leaked.","TWN":"據悉，疑似查雷德管理局Senior的人物被殺害，現場的一些照片已經在社群網路上流傳開來。"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 사진은 빠르게 삭제되었으나 그 진위 여부에 대해 관리국 관계자 측에선 아직 별다른 해명이 없는 것으로…","JPN":"この写真は直ちに削除されましたが、その真偽のほどについては管理局の関係者から、まだ弁明されていない模様です……","ENG":"The photos were quickly removed, but the Administration has made no particular statement about the authenticity of the photos...","TWN":"這些照片很快就被刪除，但管理局仍未對照片真實與否公開表態……"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"세상이 미쳐 돌아가네. 샤레이드 시니어가 죽은 것도 모자라 현장 사진이 퍼진다고?","JPN":"世の中どうかしてるわね。シャレードのシニアが死んだだけでも騒ぎなのに、現場写真まで広まってるの？","ENG":"The world's gone mad. A Charade Senior is dead, and now the scene's gone viral?","TWN":"這個世界真是瘋了。查雷德Senior死了還不夠，現場照片還被傳播出去？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"멸망할 거면 나 죽은 뒤에나 할 것이지. 왜 한창 팔팔할 때 이 지경이야?","JPN":"滅びるにしても、私が死んだ後にしてほしいわ。なんで一番元気なときにこんな目に遭うのよ？","ENG":"If the world's going to end, it could at least wait till after I'm dead. Why now, while I'm still in my prime?","TWN":"如果要滅亡，至少等我死後再來吧。為什麼偏偏在我正活躍的時候變成這樣？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"메데이아 경. 부단장님으로부터의 전언입니다.","JPN":"メデイア卿。副団長からの伝言です。","ENG":"Dame Medea, a message from the Deputy.","TWN":"美狄亞。副團長的傳話。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"곧 블루시프트 단원들이 현장에 도착한다고 합니다.","JPN":"まもなくブルーシフトの団員たちが現場に到着するとのことです。","ENG":"Blue Shift members will be arriving on-site shortly.","TWN":"藍移小組成員即將抵達現場。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"동부 방어선은 이걸로 안심이네요. 그 외, 다른 쪽은 어떤가요?","JPN":"東部防御線はこれで安心ですわね。その他の状況はどうですか？","ENG":"The eastern defense line is secured.. What about the other sections?","TWN":"東部防線這樣就放心了。那麼其他地方怎麼樣？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"서부 뉴 하이랜드 및 남동부 메리데일 방어선 모두, 타 태스크포스와 협력 중에 있습니다.","JPN":"西部のニューハイランドおよび南東部のメリーデールの防御線も、他のタスクフォースと連携中です。","ENG":"Western New Highland and southeastern Meridale defense lines are currently collaborating with other TASKFORCEs.","TWN":"西部新高地和東南部梅裡代爾防線均在與其他特遣勢力合作中。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"추가적인 지원이 필요하다 여기신다면 저희 쪽에서 인력을 차출하겠습니다.","JPN":"追加支援が必要とお考えでしたら、こちらから人員を派遣いたします。","ENG":"If you feel additional support is needed, we can deploy some of our own.","TWN":"如果你覺得需要額外的支援，我們會從這邊派遣人力。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮습니다. 정말 급한 상황이라면 상부에서 연락이 올 거예요.","JPN":"結構です。もし本当に急ぎの事態なら、上層部から直接連絡が来るはずですから。","ENG":"No need. If it were urgent, headquarters would've called already.","TWN":"沒關係。如果真的有緊急情況，上級會聯絡的。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부의 인원도 많지 않으니, 우선-.","JPN":"本部の人手も限られていますし、まずは……","ENG":"Our personnel here aren't unlimited either, so for now–","TWN":"總部人員也不多，所以先-"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"메데이아 경! 로터스 지부 단원으로부터의 연락입니다!","JPN":"メデイア卿！　ロータス支部の団員からの報告です！","ENG":"Dame Medea! A report just came in from the Lotus branch!","TWN":"美狄亞！來自洛德斯分部成員的聯繫！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"샤레이드의 침식사태 발발 이후, 로터스 국경지대에 도움을 주던 중.","JPN":"シャレードの侵食事態発生後、ロータス国境地帯で支援に当たっていた中で……","ENG":"While assisting near the Lotus border during the Charade Corruption disaster,","TWN":"在查雷德的侵蝕事件爆發後，協助洛德斯邊境地區。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"입국 심사를 거친 명단을 확인하던 차에 익숙한 이름을 발견했다고 합니다!","JPN":"入国審査を経た名簿に見覚えのある名前を発見したそうです！","ENG":"they reviewed the entry logs and spotted a familiar name!","TWN":"在檢查入境審查名單時，發現了一個熟悉的名字！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"익숙한 이름이요?","JPN":"見覚えのある名前……？","ENG":"A familiar name?","TWN":"耳熟的名字嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"그, 그게 오지만… 아니, 줄리아 레온하르트가 로터스 국경을 넘었다고 합니다.","JPN":"そ、それが……オジマン……いえ、ジュリア・レオンハルトがロータスの国境を越えたとのことです。","ENG":"It's Ozym– I mean, Julia... Julia Leonhardt crossed the Lotus border.","TWN":"那，那是喔…不，聽說茱莉亞·里恩哈特越過了洛德斯邊境。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"샤레이드 관리국 관계자의 말에 의하면 상부의 명령 없는 독단이라더군요.","JPN":"シャレード管理局関係者によると、上層部の命令なしに独断で動いたそうで。","ENG":"According to the Administration sources, she acted on her own without orders from above.","TWN":"據查雷德管理局的相關人員說，這是未經上級命令的擅自行動。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"현장의 단원들도 본부의 판단을 기다리고 있습니다만. 어떻게 할까요?","JPN":"現場の隊員たちも本部の判断を待っていますが、どうしましょう？","ENG":"The knights on-site are awaiting further instructions. How shall we proceed?","TWN":"現場的隊員們也在等待總部的判斷。我們該怎麼辦？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……잠시만요. 생각을 조금 정리할게요.","JPN":"……少し考えを整理させてください。","ENG":"...Give me a moment. I need to think.","TWN":"……稍等。我整理一下思緒。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 이런 상황에 관리국 공인 카운터가 자리를 비운다고?","JPN":"どういうこと？　こんな状況で、管理局公認のカウンターが持ち場を離れるなんて？","ENG":"What is this? An Administration confirmed Counter gone rogue in a crisis like this?","TWN":"怎麼回事？在這種情況下，管理局認證的制裁者竟然不在場？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"줄리아는 바보가 아니야. 관리국에 보고 없이 움직인 데에는 분명 이유가 있어.","JPN":"ジュリアはバカじゃない。管理局に報告もせずに動くのには、それ相応の理由があるはず。","ENG":"Julia is no fool. If she acted without reporting it, she must've had a reason.","TWN":"茱莉亞不是傻瓜。她沒有向管理局報告就行動，肯定有原因。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이번 침식 사태와 관련 있는 일이라면 상황을 방치할 수도 없는 노릇인데…….","JPN":"今回の侵食事態に関わることなら、見過ごすわけにもいかない……","ENG":"If it's tied to this Corruption disaster, we can't just sit back and watch...","TWN":"如果這件事與這次侵蝕事件有關，那就不能放任不管了……"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……짜증나. 원래 이런 판단은 내 몫이 아니라고.","JPN":"……いやになるわ。こんなの、本来私が判断することじゃないのに。","ENG":"...Ugh. This kind of decision isn't supposed to be my job.","TWN":"……真煩。這種判斷本來就不該由我來做。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};